# DK VLV.  Vemb - Lemvig
#
let vl = path("d3.dk.vlv");

with detail = 4, railway = :first :pax {
    # point.dk.Vemb  dk.LES

    with link = "line.dk.VLV" {
        track(:ror,
                vl[:vem.yl - 0.1dl, :vem.yl] << 1ms << 1mt
            ..  vl[:vem.xl, :vem.xl + 0.1dl]
        );
        track(vl[:vem.xl, :vem.xl + 2.21km]);
        line_label(:left:e, vl[:vem.xl + 2.2km] << 0.5mt, (0dt, 0.1dt), "VLV");
        track(vl[:vem.xl + 2.19km, :ams - 0.49sw]);
    }

    with link = "point.dk.Amstrup", railway = :station {
        track(vl[:ams - 0.5sw, :ams + 0.5sw]);
        marker(:left :de.hp, vl[:ams] << 0.5mt);
        station(:left, vl[:ams] << 0.5mt << 1sh + (-1.8dt, 1.5dt),
            "Amstrup", "VLV: 5,5"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:ams + 0.49sw, :bak - 0.49sw]);
    }

    with link = "point.dk.Bækmarksbro", railway = :station {
        track(vl[:bak - 0.5sw, :bak + 0.5sw]);
        marker(:right :de.bf, vl[:bak] >> 0.5mt);
        station(:right, vl[:bak] >> 0.5mt >> 1sh + (2.3dt, 0.5dt),
            "Bækmarksbro", "VLV: 8,3"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:bak + 0.49sw, :raa - 0.49sw]);
    }

    with link = "point.dk.Raakjær", railway = :station {
        track(vl[:raa - 0.5sw, :raa + 0.5sw]);
        marker(:right :de.hp :removed, vl[:raa] >> 0.5mt);
        station(:right :removed, vl[:raa] >> 0.5mt >> 1sh + (2.0dt, 0.9dt),
            "Raakjær", "VLV: 10,9"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:raa + 0.49sw, :sin - 0.49sw]);
    }

    with link = "point.dk.Sinkbæk", railway = :station {
        track(vl[:sin - 0.5sw, :sin + 0.5sw]);
        marker(:right :de.hp, vl[:sin] >> 0.5mt);
        station(:right, vl[:sin] >> 0.5mt >> 1sh + (2.0dt, 1dt),
            "Sinkbæk", "VLV: 11,6"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:sin + 0.49sw, :far - 0.49sw]);
    }

    with link = "point.dk.Fåre", railway = :station {
        track(vl[:far - 0.5sw, :far + 0.5sw]);
        marker(:left :de.bf, vl[:far] << 0.5mt);
        station(:left:right_align, vl[:far] << 0.5mt << 1sh + (-2dt, 2dt),
            "Fåre", "VLV: 13,8"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:far + 0.49sw, :far + 1.51km]);
        line_label(:right:sw, vl[:far + 1.5km] >> 0.5mt, "VLV");
        track(vl[:far + 1.49km, :ram - 0.49sw]);
    }

    with link = "point.dk.Ramme", railway = :station {
        track(vl[:ram - 0.5sw, :ram + 0.5sw]);
        marker(:right :de.bf, vl[:ram] >> 0.5mt);
        station(:right, vl[:ram] >> 0.5mt >> 1sh + (2.3dt, 0dt),
            "Ramme", "VLV: 18,9"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:ram + 0.49sw, :bon - 0.49sw]);
    }

    with link = "point.dk.Bonnet", railway = :station {
        track(vl[:bon - 0.5sw, :bon + 0.5sw]);
        marker(:left :de.bf, vl[:bon] << 0.5mt);
        station(:top, vl[:bon] << 0.5mt << 1sh + (-1.3dt, -1.0dt),
            "Bonnet", "VLV: 23,0"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:bon + 0.49sw, :lom - 0.49sw]);
    }

    with link = "point.dk.Lomborg", railway = :station {
        track(vl[:lom - 0.5sw, :lom + 0.5sw]);
        marker(:left :de.hp :removed, vl[:lom] << 0.5mt);
        station(:top :removed, vl[:lom] << 0.5mt << 1sh + (-0.5dt, -0.8dt),
            "Lomborg", "VLV: 24,5"
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:lom + 0.49sw, :arm - 0.49sw]);
    }

    with link = "point.dk.Armose", railway = :station {
        track(vl[:arm - 0.5sw, :arm + 0.5sw]);
        marker(:right :de.hp, vl[:arm] >> 0.5mt);
        label(vl[:arm] >> 0.5mt >> 1sh + (2.3dt, 2.2dt),
            vbox(:left:base,
                hbox(:left:base, " ", span(:former, "Lomborg")),
                vbox(:center:topbase,
                    "Armose",
                    span(:xsmall, "VLV: 25,9")
                )
            )
        );
    }

    with link = "line.dk.VLV" {
        track(vl[:arm + 0.49sw, :arm + 1.31km]);
        line_label(:right:nw, vl[:arm + 1.3km] >> 0.5mt, "VLV");
        track(vl[:arm + 1.29km, :lem.xt]);
        track(:lor, vl[:lem.xt - 0.1dl, :lem.yt]);
    }

    with link = "point.dk.Lemvig", railway = :station {
        track(vl[:lem.yt, :lem.f] << 1mo);
        track(vl[:lem.yt, :lem.f]);
        marker(:right :de.bf, vl[:lem] >> 0.5mt);
        station(:right, vl[:lem] >> 0.5mt >> 1sh + (2dt, 2.3dt),
            span(:bold, "Lemvig"),
            hbox(:center:top,
                vbox(:right:top, "LTY: ", "VLV: "),
                vbox(:sep:top,
                    hbox(:sep:base, "0,", anchor(), "0"),
                    hbox(:sep:base, "28,", anchor(), "8")
                )
            )
        );
    }
}

